import React, { useEffect, useState } from "react";
import API from "../services/api";
import Navbar from "../components/Navbar";

function Users() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);

  const currentUserId = localStorage.getItem("userId");

  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const res = await API.get("/users");
      setUsers(res.data);
    } catch (error) {
      console.error("Error fetching users:", error);
      alert("Failed to fetch users");
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (String(id) === String(currentUserId)) {
      alert("You cannot delete your own logged-in account.");
      return;
    }

    const confirmDelete = window.confirm(
      "Are you sure you want to delete this user?"
    );
    if (!confirmDelete) return;

    try {
      await API.delete(`/users/${id}`);
      alert("User deleted successfully");
      fetchUsers();
    } catch (error) {
      console.error("Error deleting user:", error);
      alert("Failed to delete user");
    }
  };

  return (
    <div style={styles.page}>
      <Navbar />

      <div style={styles.container}>
        <div style={styles.header}>
          <h1 style={styles.title}>Users Management</h1>
          <p style={styles.subtitle}>
            View all registered users and manage user accounts from one place.
          </p>
        </div>

        <div style={styles.section}>
          <h2 style={styles.sectionTitle}>Registered Users</h2>

          {loading ? (
            <p>Loading users...</p>
          ) : users.length === 0 ? (
            <p>No users found.</p>
          ) : (
            <div style={styles.grid}>
              {users.map((user) => (
                <div key={user.id} style={styles.userCard}>
                  <h3 style={styles.userName}>{user.username}</h3>
                  <p><strong>Email:</strong> {user.email}</p>
                  <p><strong>Role:</strong> {user.role}</p>
                  <p><strong>User ID:</strong> {user.id}</p>

                  <div style={styles.actionRow}>
                    <button
                      style={
                        String(user.id) === String(currentUserId)
                          ? styles.disabledBtn
                          : styles.deleteBtn
                      }
                      onClick={() => handleDelete(user.id)}
                      disabled={String(user.id) === String(currentUserId)}
                    >
                      {String(user.id) === String(currentUserId)
                        ? "Current User"
                        : "Delete"}
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background: "linear-gradient(135deg, #eef2ff, #f8fafc)",
    fontFamily: "Arial, sans-serif",
  },
  container: {
    width: "90%",
    maxWidth: "1200px",
    margin: "0 auto",
    padding: "30px 0 50px",
  },
  header: {
    background: "linear-gradient(135deg, #ffffff, #eff6ff)",
    padding: "30px",
    borderRadius: "20px",
    boxShadow: "0 10px 24px rgba(0,0,0,0.08)",
    marginBottom: "25px",
  },
  title: {
    fontSize: "2.2rem",
    color: "#111827",
    marginBottom: "10px",
  },
  subtitle: {
    color: "#4b5563",
    fontSize: "1rem",
    lineHeight: "1.7",
  },
  section: {
    marginTop: "20px",
  },
  sectionTitle: {
    fontSize: "1.5rem",
    marginBottom: "20px",
    color: "#111827",
  },
  grid: {
    display: "grid",
    gridTemplateColumns: "repeat(auto-fit, minmax(260px, 1fr))",
    gap: "20px",
  },
  userCard: {
    background: "#fff",
    borderRadius: "16px",
    padding: "22px",
    boxShadow: "0 8px 18px rgba(0,0,0,0.08)",
    lineHeight: "1.7",
  },
  userName: {
    color: "#111827",
    marginBottom: "12px",
  },
  actionRow: {
    display: "flex",
    gap: "10px",
    marginTop: "15px",
  },
  deleteBtn: {
    background: "#dc2626",
    color: "#fff",
    border: "none",
    padding: "10px 14px",
    borderRadius: "8px",
    cursor: "pointer",
    fontWeight: "bold",
  },
  disabledBtn: {
    background: "#9ca3af",
    color: "#fff",
    border: "none",
    padding: "10px 14px",
    borderRadius: "8px",
    cursor: "not-allowed",
    fontWeight: "bold",
  },
};

export default Users;
